import { ref } from 'vue'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'
import {
    AffiliateDateRangeFilters,
    AffiliateMeDashboard,
    AffiliateMePayoutHistoryResponse,
    AffiliateMePayoutHistoryRow,
    AffiliateMePromoCodeRow,
    AffiliateMePromoCodeSummary,
    AffiliateMePromoCodesResponse,
} from '../types'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })

const defaultDashboard: AffiliateMeDashboard = {
    unpaidCommission: 0,
    paidCommission: 0,
    totalUsageCount: 0,
}

const defaultPromoSummary: AffiliateMePromoCodeSummary = {
    totalUsageCount: 0,
    totalCommissionAmount: 0,
}

const toNumber = (value: unknown, fallback = 0): number => {
    const num = Number(value)
    return Number.isFinite(num) ? num : fallback
}

const toIsoString = (date: Date | null): string | undefined => {
    if (!date) return undefined
    if (Number.isNaN(date.getTime())) return undefined
    return date.toISOString()
}

export const useAffiliateMe = () => {
    const isLoadingDashboard = ref(false)
    const isLoadingPromoCodes = ref(false)
    const isLoadingPayoutHistory = ref(false)

    const dashboard = ref<AffiliateMeDashboard>({ ...defaultDashboard })

    const promoCodeRows = ref<AffiliateMePromoCodeRow[]>([])
    const promoCodeSummary = ref<AffiliateMePromoCodeSummary>({ ...defaultPromoSummary })
    const promoCodesPagination = makePaginationRef()

    const payoutRows = ref<AffiliateMePayoutHistoryRow[]>([])
    const payoutPagination = makePaginationRef()
    const payoutFilters = ref<AffiliateDateRangeFilters>({ from: null, to: null })

    const fetchDashboard = async () => {
        isLoadingDashboard.value = true
        try {
            const { data } = await api.axiosInstance.get('/affiliate/me/dashboard')
            const response = data?.data || {}
            dashboard.value = {
                unpaidCommission: toNumber(response.unpaidCommission),
                paidCommission: toNumber(response.paidCommission),
                totalUsageCount: toNumber(response.totalUsageCount),
            }
        } catch (error) {
            console.error('Error fetching affiliate dashboard:', error)
            dashboard.value = { ...defaultDashboard }
        } finally {
            isLoadingDashboard.value = false
        }
    }

    const fetchPromoCodes = async () => {
        isLoadingPromoCodes.value = true
        try {
            const params = {
                page: promoCodesPagination.value.page,
                limit: promoCodesPagination.value.perPage,
            }
            const { data } = await api.axiosInstance.get('/affiliate/me/promo-codes', { params })
            const response = data as Partial<AffiliateMePromoCodesResponse>

            promoCodeRows.value = (response.data || []).map((item) => ({
                code: item.code || '',
                usageCount: toNumber(item.usageCount),
                commissionTotal: toNumber(item.commissionTotal),
            }))

            const summary = response.summary || defaultPromoSummary
            promoCodeSummary.value = {
                totalUsageCount: toNumber(summary.totalUsageCount),
                totalCommissionAmount: toNumber(summary.totalCommissionAmount),
            }

            ignorePromoPaginationUpdates(() => {
                promoCodesPagination.value = {
                    page: toNumber(response.page, promoCodesPagination.value.page),
                    perPage: toNumber(response.limit, promoCodesPagination.value.perPage),
                    total: toNumber(response.total),
                }
            })
        } catch (error) {
            console.error('Error fetching affiliate promo codes:', error)
            promoCodeRows.value = []
            promoCodeSummary.value = { ...defaultPromoSummary }
        } finally {
            isLoadingPromoCodes.value = false
        }
    }

    const fetchPayoutHistory = async () => {
        isLoadingPayoutHistory.value = true
        try {
            const params: Record<string, string | number> = {
                page: payoutPagination.value.page,
                limit: payoutPagination.value.perPage,
            }

            const fromIso = toIsoString(payoutFilters.value.from)
            const toIso = toIsoString(payoutFilters.value.to)
            if (fromIso) params.from = fromIso
            if (toIso) params.to = toIso

            const { data } = await api.axiosInstance.get('/affiliate/me/payout-history', { params })
            const response = data as Partial<AffiliateMePayoutHistoryResponse>

            payoutRows.value = (response.data || []).map((item) => ({
                id: toNumber(item.id),
                payoutDate: item.payoutDate || '',
                amount: toNumber(item.amount),
                note: item.note || '',
            }))

            ignorePayoutPaginationUpdates(() => {
                payoutPagination.value = {
                    page: toNumber(response.page, payoutPagination.value.page),
                    perPage: toNumber(response.limit, payoutPagination.value.perPage),
                    total: toNumber(response.total),
                }
            })
        } catch (error) {
            console.error('Error fetching affiliate payout history:', error)
            payoutRows.value = []
        } finally {
            isLoadingPayoutHistory.value = false
        }
    }

    const setPromoCodesPage = (page: number) => {
        promoCodesPagination.value.page = page
    }

    const setPromoCodesPerPage = (perPage: number) => {
        promoCodesPagination.value.perPage = perPage
        promoCodesPagination.value.page = 1
    }

    const setPayoutPage = (page: number) => {
        payoutPagination.value.page = page
    }

    const setPayoutPerPage = (perPage: number) => {
        payoutPagination.value.perPage = perPage
        payoutPagination.value.page = 1
    }

    const setPayoutDateRange = (from: Date | null, to: Date | null) => {
        payoutFilters.value = { from, to }
        payoutPagination.value.page = 1
    }

    const refreshAll = async () => {
        await Promise.all([fetchDashboard(), fetchPromoCodes(), fetchPayoutHistory()])
    }

    const { ignoreUpdates: ignorePromoPaginationUpdates } = watchIgnorable([promoCodesPagination], fetchPromoCodes, {
        deep: true,
    })

    const { ignoreUpdates: ignorePayoutPaginationUpdates } = watchIgnorable([payoutPagination], fetchPayoutHistory, {
        deep: true,
    })

    refreshAll()

    return {
        isLoadingDashboard,
        isLoadingPromoCodes,
        isLoadingPayoutHistory,

        dashboard,

        promoCodeRows,
        promoCodeSummary,
        promoCodesPagination,

        payoutRows,
        payoutPagination,
        payoutFilters,

        fetchDashboard,
        fetchPromoCodes,
        fetchPayoutHistory,
        refreshAll,

        setPromoCodesPage,
        setPromoCodesPerPage,
        setPayoutPage,
        setPayoutPerPage,
        setPayoutDateRange,
    }
}
